type UnionFind struct {
    parent []int64
    rank   []int64
}

func NewUnionFind(n int64) *UnionFind {
    parent := make([]int64, n+1)
    rank := make([]int64, n+1)
    var i int64
    for i = 1; i <= n; i++ {
        parent[i] = i
        rank[i] = 0
    }
    return &UnionFind{parent, rank}
}

func (uf *UnionFind) find(x int64) int64 {
    if uf.parent[x] != x {
        uf.parent[x] = uf.find(uf.parent[x])
    }
    return uf.parent[x]
}

func (uf *UnionFind) union(x, y int64) {
    rx := uf.find(x)
    ry := uf.find(y)
    if rx == ry {
        return
    }
    if uf.rank[rx] < uf.rank[ry] {
        uf.parent[rx] = ry
    } else if uf.rank[rx] > uf.rank[ry] {
        uf.parent[ry] = rx
    } else {
        uf.parent[ry] = rx
        uf.rank[rx]++
    }
}

type MinHeap struct {
    arr []int64
    pos map[int64]int
}

func (h *MinHeap) Len() int {
    return len(h.arr)
}

func (h *MinHeap) swap(i, j int) {
    h.arr[i], h.arr[j] = h.arr[j], h.arr[i]
    h.pos[h.arr[i]] = i
    h.pos[h.arr[j]] = j
}

func (h *MinHeap) up(i int) {
    for i > 0 {
        parent := (i - 1) / 2
        if h.arr[parent] <= h.arr[i] {
            break
        }
        h.swap(i, parent)
        i = parent
    }
}

func (h *MinHeap) down(i int) {
    n := h.Len()
    for i < n {
        smallest := i
        left := 2*i + 1
        right := 2*i + 2
        if left < n && h.arr[left] < h.arr[smallest] {
            smallest = left
        }
        if right < n && h.arr[right] < h.arr[smallest] {
            smallest = right
        }
        if smallest == i {
            break
        }
        h.swap(i, smallest)
        i = smallest
    }
}

func (h *MinHeap) Push(x int64) {
    h.arr = append(h.arr, x)
    h.pos[x] = len(h.arr) - 1
    h.up(len(h.arr) - 1)
}

func (h *MinHeap) Remove(x int64) {
    idx, ok := h.pos[x]
    if !ok {
        return
    }
    n := h.Len()
    h.swap(idx, n-1)
    h.arr = h.arr[:n-1]
    delete(h.pos, x)
    if idx < n-1 {
        if idx > 0 && h.arr[idx] < h.arr[(idx-1)/2] {
            h.up(idx)
        } else {
            h.down(idx)
        }
    }
}

func (h *MinHeap) Top() int64 {
    if h.Len() == 0 {
        return -1
    }
    return h.arr[0]
}

func solve(c int64, connections [][]int64, queries [][]int64) []int64 {
    uf := NewUnionFind(c)
    for _, conn := range connections {
        u, v := conn[0], conn[1]
        uf.union(u, v)
    }

    compIDMap := make([]int64, c+1)
    for i := int64(1); i <= c; i++ {
        compIDMap[i] = uf.find(i)
    }

    compNodes := make(map[int64][]int64)
    for i := int64(1); i <= c; i++ {
        compID := compIDMap[i]
        compNodes[compID] = append(compNodes[compID], i)
    }

    online := make([]bool, c+1)
    for i := int64(1); i <= c; i++ {
        online[i] = true
    }

    compHeaps := make(map[int64]*MinHeap)
    for compID, nodes := range compNodes {
        h := &MinHeap{
            arr: make([]int64, 0),
            pos: make(map[int64]int),
        }
        for _, node := range nodes {
            h.Push(node)
        }
        compHeaps[compID] = h
    }

    result := []int64{}
    for _, q := range queries {
        op := q[0]
        x := q[1]
        if op == 1 {
            if online[x] {
                result = append(result, x)
            } else {
                compID := compIDMap[x]
                heap := compHeaps[compID]
                if heap.Len() == 0 {
                    result = append(result, -1)
                } else {
                    result = append(result, heap.Top())
                }
            }
        } else if op == 2 {
            if online[x] {
                online[x] = false
                compID := compIDMap[x]
                heap := compHeaps[compID]
                heap.Remove(x)
            }
        }
    }

    return result
}
