type UnionFind struct {
	parent []int64
}

func NewUnionFind(size int64) *UnionFind {
	parent := make([]int64, size+1)
	for i := int64(1); i <= size; i++ {
		parent[i] = i
	}
	return &UnionFind{parent: parent}
}

func (uf *UnionFind) Find(x int64) int64 {
	if uf.parent[x] != x {
		uf.parent[x] = uf.Find(uf.parent[x])
	}
	return uf.parent[x]
}

func (uf *UnionFind) Union(x, y int64) {
	rootX := uf.Find(x)
	rootY := uf.Find(y)
	if rootX != rootY {
		if rootX < rootY {
			uf.parent[rootY] = rootX
		} else {
			uf.parent[rootX] = rootY
		}
	}
}

func solve(c int64, connections [][]int64, queries [][]int64) []int64 {
	uf := NewUnionFind(c)
	for _, conn := range connections {
		u, v := conn[0], conn[1]
		uf.Union(u, v)
	}

	online := make(map[int64]bool)
	for i := int64(1); i <= c; i++ {
		online[i] = true
	}

	componentMin := make(map[int64]int64)
	for i := int64(1); i <= c; i++ {
		root := uf.Find(i)
		if _, exists := componentMin[root]; !exists {
			componentMin[root] = i
		} else {
			if i < componentMin[root] {
				componentMin[root] = i
			}
		}
	}

	result := []int64{}
	for _, query := range queries {
		typ, x := query[0], query[1]
		if typ == 1 {
			if online[x] {
				result = append(result, x)
			} else {
				root := uf.Find(x)
				minOnline := int64(-1)
				// Need to find the smallest online node in the component
				// Since the componentMin[root] is the smallest node in the component,
				// but it might be offline. So we need to track the smallest online node per component.
				// To optimize, we can maintain a map of component root to a sorted list of online nodes.
				// But for large c, this is not feasible. So we need a better approach.
				// For now, we'll iterate through all nodes in the component to find the smallest online node.
				// This is not efficient but works for small inputs.
				// For large inputs, we need a more efficient data structure.
				for i := int64(1); i <= c; i++ {
					if uf.Find(i) == root && online[i] {
						if minOnline == -1 || i < minOnline {
							minOnline = i
						}
					}
				}
				result = append(result, minOnline)
			}
		} else if typ == 2 {
			online[x] = false
			// When a node goes offline, we need to update the componentMin if necessary
